// Get access token from Severa API using client_credentials grant.
// No refresh token needed: this is the initial token request.
// Reads client_id and client_secret from the previous "Severa credentials" (Edit Fields) node.

const SEVERA_BASE = 'https://api.severa.visma.com/rest-api';
const inputItem = $input.first();
const clientId = inputItem.json.client_id;
const clientSecret = inputItem.json.client_secret;

if (!clientId || !clientSecret) {
  throw new Error(
    'Missing client_id or client_secret. Set them in the "Severa credentials" Edit Fields node.'
  );
}

const tokenUrl = `${SEVERA_BASE}/v1/login/oauth/token`;
const body = {
  grant_type: 'client_credentials',
  client_id: clientId,
  client_secret: clientSecret,
  scope: 'projects:read',
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: tokenUrl,
  body,
  json: true,
});

if (!response.access_token) {
  throw new Error(
    'Token response did not contain access_token. Check client_id and client_secret in the Severa credentials node.'
  );
}

// Pass through credentials and add token (and refresh_token if API returned one).
return [
  {
    json: {
      ...inputItem.json,
      access_token: response.access_token,
      refresh_token: response.refresh_token || null,
      expires_in: response.expires_in,
      token_type: response.token_type || 'Bearer',
    },
  },
];

// Pull all proposals from Severa API (all pages).
// Uses access_token from the previous "Get Severa Access Token" node.
// Paginates automatically (rowCount=100, NextPageToken).

const SEVERA_BASE = 'https://api.severa.visma.com/rest-api';
const ROW_COUNT = 100;

const inputItem = $input.first();
const accessToken = inputItem.json.access_token;

if (!accessToken) {
  throw new Error('No access_token in input. Run "Get Severa Access Token" first.');
}

const headers = {
  Authorization: `Bearer ${accessToken}`,
  Accept: 'application/json',
};

let allProposals = [];
let pageToken = null;

do {
  let url = `${SEVERA_BASE}/v1/proposals?rowCount=${ROW_COUNT}`;
  if (pageToken) {
    url += '&pageToken=' + encodeURIComponent(pageToken);
  }

  let response;
  try {
    response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers,
      json: true,
      returnFullResponse: true,
    });
  } catch (err) {
    if (err.response && err.response.status === 403) {
      const data = err.response.data;
      const msg = (data && (data.message || data.error_description || (typeof data === 'string' ? data : JSON.stringify(data)))) || err.message;
      throw new Error('Severa API 403 Forbidden. Ensure your REST API client has projects:read (Proposals) permission in Severa Rest Api settings. ' + msg);
    }
    throw err;
  }

  const page = Array.isArray(response.body) ? response.body : [];
  allProposals = allProposals.concat(page);

  const h = response.headers || {};
  pageToken = h.nextpagetoken || h.NextPageToken || null;
} while (pageToken);

return allProposals.map((p) => ({ json: p }));
